import { ServiceNowEvents } from './utils/events.js';
import { createComponent } from './utils/createComponent.js';

/**
 * Card component - A React wrapper for the now-card web component
 */
const Card = createComponent({
 tagName: 'now-card',
 displayName: 'Card',
 eventMap: {
 onClicked: ServiceNowEvents.CARD.CLICKED,
 onSelectedSet: ServiceNowEvents.CARD.SELECTED_SET
