","import React, { useEffect, useState } from "react";
import { Card } from "@servicenow/react-components/Card";
import { CardHeader } from "@servicenow/react-components/CardHeader";

const BASE = "/api/now/stats/x_184699_ai_expe_0_run";
const headers = { Accept: "application/json", "X-UserToken": (window as any).g_ck };

const DashboardMetrics: React.FC = () => {
 const [totalRuns, setTotalRuns] = useState<number | null>(null);
 const [avgScore, setAvgScore] = useState<number | null>(null);
 const [totalCost, setTotalCost] = useState<number | null>(null);
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 const fetchAll = async () => {
 try {
 const [countRes, avgRes, sumRes] = await Promise.all([
 fetch(`${BASE}?sysparm_count=true`, { headers }),
 fetch(`${BASE}?sysparm_avg_fields=score`, { headers }),
 fetch(`${BASE}?sysparm_sum_fields=cost_estimate`, { headers }),
 ]);
 const countData = await countRes.json();
 const avgData = await avgRes.json();
 const sumData = await sumRes.json();

 setTotalRuns(Number(countData.result.stats.count));
 setAvgScore(Number(avgData.result.stats.avg.score));
 setTotalCost(Number(sumData.result.stats.sum.cost_estimate));
 } catch (e) {
 console.error("Failed to fetch metrics", e);
 } finally {
 setLoading(false);
 }
 };
 fetchAll();
 }, []);

 if (loading) return <p className="loading-text">Loading metrics…</p>;

 return (
 <div className="metrics-grid">
 <Card interaction="none" size="md" sidebar={{ color: "info", variant: "primary" }}>
 <CardHeader heading={{ label: "Total Runs" }} />
 <span className="metric-value">{totalRuns ?? "—"}</span>
 </Card>
 <Card interaction="none" size="md" sidebar={{ color: "positive", variant: "primary" }}>
 <CardHeader heading={{ label: "Average Score" }} />
 <span className="metric-value">
 {avgScore !== null ? `${avgScore.toFixed(1)}/5` : "—"}
 </span>
 </Card>
 <Card interaction="none" size="md" sidebar={{ color: "warning", variant: "primary" }}>
 <CardHeader heading={{ label: "Total Cost" }} />
 <span className="metric-value">
 {totalCost !== null ? `$${totalCost.toFixed(2)}` : "—"}
 </span>
 </Card>
 </div>
 );
};

export default DashboardMetrics;
