interface GroupEntry {
 label: string;
 count: number;
}

const URL =
 "/api/now/stats/x_184699_ai_expe_0_run?sysparm_count=true&sysparm_group_by=experiment&sysparm_display_value=true";
const headers = { Accept: "application/json", "X-UserToken": (window as any).g_ck };

const RunsPerExperiment: React.FC = () => {
 const [data, setData] = useState<GroupEntry[]>([]);
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 const fetchData = async () => {
 try {
 const res = await fetch(URL, { headers });
 const json = await res.json();
 const entries: GroupEntry[] = (json.result || []).map((item: any) => ({
 label: item.groupby_fields?.[0]?.display_value || "Unknown",
 count: Number(item.stats.count),
 }));
 setData(entries);
 } catch (e) {
 console.error("Failed to fetch runs per experiment", e);
 } finally {
 setLoading(false);
 }
 };
 fetchData();
 }, []);

 const max = Math.max(...data.map((d) => d.count), 1);

 if (loading) return <p className="loading-text">Loading chart…</p>;
 if (!data.length) return <p className="no-data-text">No run data available</p>;

 return (
 <div className="bar-section">
 <CardHeader heading={{ label: "Runs per Experiment" }} />
 {data.map((entry) => (
 <Card key={entry.label} interaction="none" size="sm">
 <div className="bar-row">
 <span className="bar-label">{entry.label}</span>
 <div className="bar-track">
 <div
 className="bar-fill"
 style={{ width: `${(entry.count / max) * 100}%` }}
 />
 </div>
 <span className="bar-count">{entry.count}</span>
 </div>
 </Card>
 ))}
 </div>
 );
};

export default RunsPerExperiment;
