",".dashboard {
 max-width: 1200px;
 margin: 0 auto;
 padding: 2rem;
}

.dashboard-title {
 font-size: 1.75rem;
 font-weight: 700;
 color: rgb(var(--now-color--text--primary, 22, 27, 28));
 margin: 0 0 1.5rem 0;
}

.metrics-grid {
 display: grid;
 grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
 gap: 1.5rem;
 margin-bottom: 2rem;
}

.metric-value {
 font-size: 2.25rem;
 font-weight: 700;
 display: block;
 margin-top: 0.5rem;
 color: rgb(var(--now-color--text--primary, 22, 27, 28));
}

.bar-section {
 margin-bottom: 2rem;
}

.bar-row {
 display: flex;
 align-items: center;
 gap: 0.75rem;
 padding: 0.5rem 0;
}

.bar-label {
 min-width: 160px;
 font-size: 0.875rem;
 color: rgb(var(--now-color--text--secondary, 100, 106, 109));
 white-space: nowrap;
 overflow: hidden;
 text-overflow: ellipsis;
}

.bar-track {
 flex: 1;
 height: 24px;
 background: rgb(var(--now-color--neutral--2, 232, 234, 236));
 border-radius: 4px;
 overflow: hidden;
}

.bar-fill {
 height: 100%;
 background: rgb(var(--now-actionable--primary--background-color, 0, 128, 163));
 border-radius: 4px;
 transition: width 0.3s ease;
}

.bar-count {
 min-width: 30px;
 font-weight: 600;
 font-size: 0.875rem;
 text-align: right;
}

.cost-trend-section {
 margin-top: 1.5rem;
}

.loading-text {
 color: rgb(var(--now-color--text--tertiary, 150, 155, 158));
 padding: 1rem 0;
}

.no-data-text {
 color: rgb(var(--now-color--text--tertiary, 150, 155, 158));
 padding: 1rem 0;
 font-style: italic;
}
","export default function insertStyle(css, tagName = "style") {
 if (!css || typeof window === "undefined")
 return;
 if (tagName === "style") {
 const style = document.createElement("style");
 style.setAttribute("type", "text/css");
 style.innerHTML = css;
 document.head.appendChild(style);
 }
 else if (tagName === "link") {
 const link = document.createElement("link");
 link.setAttribute("rel", "stylesheet");
 link.setAttribute("href", css);
 document.head.appendChild(link);
 }
